20	// Runes and moonstones are "components" — a distinct pricing tier that shares
21	// one base premium (and, later, block/alike rules). Naming the shared value
22	// makes the equality intentional rather than a coincidence two entries happen
23	// to share.
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	// A "building block" of exactly this many alike components is offered at a
27	// special block premium instead of the per-component price.
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	
31	const BASE_PREMIUMS: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: COMPONENT_BASE_PREMIUM,
37	  moonstone: COMPONENT_BASE_PREMIUM,
38	};
39	const PROCESSING_FEE = 5;
40	
41	// Surcharges are expressed as integer percentages and applied as
42	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
43	// such as `100 * 1.1 === 100.00000000000001`).
44	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
45	const CURSE_SURCHARGE_PERCENT = 50;
46	const LOYALTY_DISCOUNT_PERCENT = 20;
47	const LOYALTY_MIN_YEARS = 2;
48	
49	const percentOf = (amount: number, percent: number): number =>
50	  (amount * percent) / 100;
51	
52	// A single item's base premium. BASE_PREMIUMS is the single source of truth
53	// for per-type base prices (components included), so a plain lookup suffices —
54	// block pricing is a group-level concern handled separately in sumBasePremiums.
55	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
56	
57	// Item-specific surcharge: a curse adds 50% of that item's own base premium.
58	const itemSurcharge = (item: Item): number =>
59	  item.cursed ? percentOf(itemBasePremium(item), CURSE_SURCHARGE_PERCENT) : 0;
60	
61	const sumItemSurcharges = (items: Item[]): number =>
62	  items.reduce((total, item) => total + itemSurcharge(item), 0);
63	
64	const countByType = (items: Item[]): Map<string, number> => {
65	  const counts = new Map<string, number>();
66	  for (const item of items) {
67	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
68	  }
69	  return counts;
70	};
71	
72	const componentGroupPremium = (count: number): number =>
73	  count === COMPONENT_BLOCK_SIZE
74	    ? COMPONENT_BLOCK_PREMIUM
75	    : count * COMPONENT_BASE_PREMIUM;
76	
77	const typeGroupPremium = (type: string, count: number): number =>
78	  COMPONENT_TYPES.has(type)
79	    ? componentGroupPremium(count)
80	    : count * (BASE_PREMIUMS[type] ?? 0);
81	
82	const sumBasePremiums = (items: Item[]): number =>
83	  [...countByType(items)].reduce(
84	    (total, [type, count]) => total + typeGroupPremium(type, count),
85	    0,
86	  );
87	
88	export const quote = (
89	  customer: Customer,
90	  step: QuoteStep,
91	  _quoteIndex: number,
92	): QuoteResult => {
93	  const policyBase = sumBasePremiums(step.items);
94	  const itemSurcharges = sumItemSurcharges(step.items);
95	  const firstInsurance = percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
96	  const loyalty =
97	    customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
98	      ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
99	      : 0;
100	  const premium = Math.ceil(
101	    policyBase + itemSurcharges + firstInsurance - loyalty + PROCESSING_FEE,
102	  );
103	  return { premium };
104	};
105	
106	export const claim = (): unknown => {
107	  return undefined;
108	};
